import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def urgency_penalty(current_time, window_close, window_open, arrival_time):
        time_left = max(window_close - current_time, 0)
        urgency_factor = 1 + (1 / (time_left + 1))  # More urgent as time left diminishes
        if arrival_time > window_close:
            return 100 * (arrival_time - window_close) * urgency_factor
        elif arrival_time < window_open:
            return 50 * (window_open - arrival_time) * urgency_factor
        else:
            return -50 * urgency_factor  # Incentive for hitting the window exactly

    def collaborative_delay(index, current_pos, all_positions, time_to_arrive):
        delay_factor = 0
        for pos in all_positions:
            if np.array_equal(pos, current_pos):
                continue
            other_time = calculate_distance(pos, unvisited_customers[index]) / truck_speed + current_time
            if other_time < time_to_arrive:
                delay_factor += (time_to_arrive - other_time) / truck_speed  # Weighted by how much earlier others can arrive
        return delay_factor

    best_node = None
    min_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        penalty = urgency_penalty(current_time, window_close, window_open, arrival_time)
        collaborative_penalty = collaborative_delay(i, cur_truck_pos, all_truck_pos, arrival_time)

        total_cost = travel_time + penalty + collaborative_penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node
